    fillKursValues(){
      if(this.nbu_kurs_value > 0){
        const kursStr = this.nbu_kurs_value.toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ');
        
        // Asosiy qarz kursini to'ldirish
        this.pay_main_debt_kurs_str = kursStr;
        this.pay_main_debt_kurs = this.nbu_kurs_value;
        
        // Barcha qarz turlari uchun kursni to'ldirish
        if(this.pay_qarz_type_list && this.pay_qarz_type_list.length > 0){
          this.pay_qarz_type_list.forEach(type => {
            type.pay_kurs_str = kursStr;
            type.pay_kurs = this.nbu_kurs_value;
          });
        }
      }
    },
    async nbuKurs(){
      try{
        const response = await fetch("https://cbu.uz/uz/arkhiv-kursov-valyut/json/");
        if(!response.ok){
          return;
        }
        const data = await response.json();
        
        if(data && data.length > 0){
          this.nbu_kurs_value = parseInt(data[0].Rate);
          this.dollor_kurs = parseInt(data[0].Rate).toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ')
          this.dollor_kurs_qty = parseInt(data[0].Rate);
        }
      }
      catch(error){
        console.log('nbuKurs error:', error);
      }
    },
