    async fetchQarzTypeForPayment(){
      this.pay_qarz_type_sum = 0;
      this.pay_qarz_type_dollor = 0;
      this.pay_qarz_type_list = [];
      if(!this.qarz_client_info || !this.qarz_client_info.id){
        return;
      }
      try{
        const response = await fetch(this.$store.state.hostname + "/TegirmonQarzUserType/getPaginationQarzType?page=0&size=100&user_id=" + this.qarz_client_info.id);
        const data = await response.json();
        console.log('fetchQarzUserType data', data)
        if(response.status == 200 || response.status == 201){
          // Kursni to'ldirish (agar hali olinmagan bo'lsa)
          const kursStr = this.nbu_kurs_value > 0 
            ? this.nbu_kurs_value.toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ')
            : '';
          const list = (data.items_list || []).map(it => ({
            ...it,
            pay_sum_str: '',
            pay_sum: 0,
            pay_dollor_str: '',
            pay_dollor: 0,
            pay_kurs_str: kursStr,
            pay_kurs: this.nbu_kurs_value || 0
          }));
          this.pay_qarz_type_list = list;
          this.pay_qarz_type_sum = list.reduce((s, it) => s + (it.sum || 0), 0);
          this.pay_qarz_type_dollor = list.reduce((s, it) => s + (it.dollor || 0), 0);
          
          // Agar kurs hali olinmagan bo'lsa, endi to'ldirish
          if(this.nbu_kurs_value > 0){
            const finalKursStr = this.nbu_kurs_value.toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ');
            this.pay_qarz_type_list.forEach(type => {
              type.pay_kurs_str = finalKursStr;
              type.pay_kurs = this.nbu_kurs_value;
            });
          }
        } else {
          this.pay_qarz_type_sum = 0;
          this.pay_qarz_type_dollor = 0;
          this.pay_qarz_type_list = [];
        }
      } catch(e){
        console.log('fetchQarzUserType error', e);
        this.pay_qarz_type_sum = 0;
        this.pay_qarz_type_dollor = 0;
        this.pay_qarz_type_list = [];
      }
    },
    async Ish_haqqi_berish(){
      let now = new Date();

      let year = now.getFullYear();
      let month = String(now.getMonth() + 1).padStart(2, '0');
      let day = String(now.getDate()).padStart(2, '0');
      let hour = String(now.getHours()).padStart(2, '0');
      let minute = String(now.getMinutes()).padStart(2, '0');

      // Har doim sekund = 00, millisekund = 000 bo‘lsin
      let new_date = `${year}-${month}-${day}T${hour}:${minute}:00.000Z`;

      let begin = this.begin_date + `T${hour}:${minute}:00.000Z`;
      let end = this.end_date + `T${hour}:${minute}:00.000Z`;

      const requestOptions = {
        method : "POST",
        headers: { "Content-Type" : "application/json" },
