    async blockAllUsersOnDevice(door) {
      // Agar door.nomer == 1 bo'lsa, unblock qilish, aks holda block qilish
      const isUnblock = door.nomer === 1;
      const actionText = isUnblock ? "blocklist'dan chiqarishni" : "blocklist'ga qo'shishni";
      const deviceName = door.acc_name || door.device;
      
      // Confirm dialog
      const confirmMessage = isUnblock 
        ? `${deviceName} deviceni Blokdan chiqarishni xoxlaysizmi?`
        : `${deviceName} devicedagi vaqtincha bloklashni xoxlaysizmi?`;
      
      if (!confirm(confirmMessage)) {
        return;
      }

      // Progress bar'ni boshlash
      this.blockingDeviceId = door.id;
      this.showBlockingProgress = true;
      this.blockingProgress = 0;

      // Progress bar animatsiyasi - 25 soniya = 25000ms, 100 foiz = har bir foiz uchun 250ms
      // Har bir foizni 1 tadan qo'shib, 250ms interval bilan
      const progressInterval = setInterval(() => {
        if (this.blockingProgress < 90) {
          this.blockingProgress = Math.floor(this.blockingProgress) + 1; // Butun sonlar bilan, 1 tadan qo'shish
          if (this.blockingProgress > 90) {
            this.blockingProgress = 90; // 90% gacha, API javob kelguncha
          }
        }
      }, 250); // Har 250ms da 1% qo'shish (25 soniya = 25000ms / 100 foiz = 250ms per foiz)
      
      try {
        const response = await fetch(this.$store.state.hostname + `/SkudDoors/blockAllUsers/${door.id}`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json'
          }
        });

        const data = await response.json();

        // Progress bar'ni birdan 100% ga o'tkazish va yopish
        clearInterval(progressInterval);
        this.blockingProgress = 100; // Birdan 100% ga o'tkazish
        
        // Progress bar'ni ko'rsatish uchun minimal delay (100ms)
        await new Promise(resolve => setTimeout(resolve, 100));

        // Progress bar'ni yopish
        this.showBlockingProgress = false;
        this.blockingProgress = 0;

        if (response.status === 200 && data.success) {
          const successCount = isUnblock ? data.unblockedCount : data.blockedCount;
          const message = isUnblock 
            ? `Muvaffaqiyatli: ${successCount} xodim blocklist'dan chiqarildi, ${data.failedCount} tasida xatolik`
            : `Muvaffaqiyatli: ${successCount} xodim blocklist'ga qo'shildi, ${data.failedCount} tasida xatolik`;
          this.$refs.message.success(message);
          
          if (data.failedCount > 0 && data.errors && data.errors.length > 0) {
            console.warn(`${actionText} xatoliklari:`, data.errors);
          }
          
          // Door list'ni yangilash
          if (successCount > 0) {
            await this.fetch_Door();
          }
        } else {
          this.$refs.message.error(data.message || `Xodimlarni ${actionText}da xatolik yuz berdi`);
          if (data.errors && data.errors.length > 0) {
            console.error('Xatoliklar:', data.errors);
          }
        }
      } catch (error) {
        // Xatolik bo'lsa ham progress bar'ni birdan 100% ga o'tkazib yopish
        clearInterval(progressInterval);
        this.blockingProgress = 100; // Birdan 100% ga o'tkazish
        
        // Minimal delay
        await new Promise(resolve => setTimeout(resolve, 100));
        
        this.showBlockingProgress = false;
        this.blockingProgress = 0;
        
        console.error('Block/Unblock all users error:', error);
        this.$refs.message.error(`Xodimlarni ${actionText}da xatolik yuz berdi`);
      } finally {
        this.blockingDeviceId = null;
      }
    },
  },

}
